INSERT INTO `blog_posts` VALUES (1,NULL,'دليل البداية السريعة: إعداد مدرستك على منصة PE Smart School','quick-start-guide-school-setup','<p>\n            </p><p>مرحباً بك في منصة <strong>PE Smart School</strong>، الشريك التقني الأول لمعلمي التربية البدنية. في هذا الدرس، سنأخذك في جولة سريعة لإعداد مدرستك والبدء في الاستفادة من ميزات المنصة.</p><p>\n            \n            </p><h2>1. تسجيل الدخول لأول مرة</h2><p>\n            </p><p>بمجرد حصولك على بيانات الدخول من مدير النظام، توجه إلى صفحة تسجيل الدخول واستخدم اسم المستخدم وكلمة المرور الخاصة بمدرستك.</p><p>\n<img src=\"http://localhost/pe1/uploads/media/media_1773030043_86ae212107.png\">            http://localhost/pe1/admin//uploads/media/media_1773030043_86ae212107.png</p><h2>2. ضبط بيانات المدرسة الأساسية</h2><p>\n            </p><p>توجه إلى قسم <strong>\"إعدادات المدرسة\"</strong> من القائمة الجانبية. هنا يمكنك:</p><p>\n            </p><p><img src=\"http://localhost/pe1/uploads/media/media_1773030069_8feaebc16c.png\"></p><p>\n            </p><p><em>[اقتراح صورة: واجهة إعدادات المدرسة]</em></p><p>\n\n            </p><h2>3. التعرف على لوحة التحكم (Dashboard)</h2><p>\n            </p><p>لوحة التحكم هي مركز العمليات. ستجد فيها إحصائيات سريعة عن:</p><p>\n          <img src=\"http://localhost/pe1/uploads/media/media_1773030060_570a21f586.png\">  </p><p><br></p><p>\n            </p><p><em>[اقتراح صورة: لوحة المعلومات الرئيسية مع الإحصائيات]</em></p><p>\n\n            </p><h2>نصيحة إضافية للسيو (SEO)</h2><p>\n            </p><p>تأكد دائماً من ملء البيانات بشكل كامل، لأن المنصة تستخدم هذه البيانات لإنشاء تقارير احترافية تعزز من صورة مدرستك أمام أولياء الأمور والوزارة.</p><p>\n\n            </p><p>في الدرس القادم، سنتعلم كيفية بناء <strong>الهيكل المدرسي</strong> وإضافة المراحل الدراسية والفصول.</p><p>\n        </p>','تعلم كيفية ضبط إعدادات مدرستك الأساسية والبدء في استخدام المنصة لتطوير قسم التربية البدنية في دقائق.','https://images.unsplash.com/photo-1544652478-6653e09f18a2?auto=format&amp;amp;amp;amp;fit=crop&amp;amp;amp;amp;q=80&amp;amp;amp;amp;w=1000','الدروس','published','2026-03-08 16:30:50',NULL,'2026-03-08 14:30:50','2026-03-09 07:18:53',1,NULL,0),(2,NULL,'الدرس الثاني: بناء الهيكل المدرسي (المراحل والفصول) في نظام PE Smart School','school-structure-grades-classes','<p class=\"ql-align-right ql-direction-rtl\">\n            </p><p class=\"ql-align-right ql-direction-rtl\">بعد إعداد بيانات مدرستك الأساسية، الخطوة التالية والأهم هي بناء <strong>الهيكل المدرسي</strong>. هذا الهيكل هو العمود الفقري الذي يربط الطلاب بالمعلمين والأنشطة الرياضية.</p><p class=\"ql-align-right ql-direction-rtl\">\n                        </p><h2 class=\"ql-align-right ql-direction-rtl\">لماذا يجب تنظيم الهيكل المدرسي؟</h2><p class=\"ql-align-right ql-direction-rtl\">\n            </p><p class=\"ql-align-right ql-direction-rtl\">التنظيم الصحيح يسمح لك بـ:</p><p class=\"ql-align-right ql-direction-rtl\">\n                     </p><h2 class=\"ql-align-right ql-direction-rtl\">1. إضافة المراحل الدراسية (Grades)</h2><p class=\"ql-align-right ql-direction-rtl\">\n            </p><p class=\"ql-align-right ql-direction-rtl\">المراحل الدراسية هي المستويات الكبرى (مثل: الصف الأول، الصف الثاني، إلخ). لإضافتها:</p><p class=\"ql-align-right ql-direction-rtl\">           </p><ol><li class=\"ql-align-right ql-direction-rtl\">يتم اختيار قائمة الصفوف والفصول من القائمة الجانبية </li><li class=\"ql-align-right ql-direction-rtl\">ثم إضافة صف </li><li class=\"ql-align-right ql-direction-rtl\">تظهر نافذة منبثقة (نافذة إضافة صف) </li><li class=\"ql-align-right ql-direction-rtl\">تدخل اسم الصف </li><li class=\"ql-align-right ql-direction-rtl\">ثم تدخل رمز الصف (اختياري)</li><li class=\"ql-align-right ql-direction-rtl\">ثم تضغط على حفظ\n                        </li></ol><p class=\"ql-align-right ql-direction-rtl\"><br></p><p class=\"ql-align-right ql-direction-rtl\"><img src=\"data:image/png;base64,\"></p><p class=\"ql-align-right ql-direction-rtl\"><br></p><h2 class=\"ql-align-right ql-direction-rtl\">2. إضافة الفصول (Classes)</h2><p class=\"ql-align-right ql-direction-rtl\">\n            </p><p class=\"ql-align-right ql-direction-rtl\">داخل كل مرحلة، توجد فصول أصغر (مثل: فصل 1/أ، فصل 1/ب). لإضافة فصل:</p><p class=\"ql-align-right ql-direction-rtl\">\n         </p><ol><li class=\"ql-align-right ql-direction-rtl\">بعد إضافة الصفوف تضغط على إضافة فصل </li><li class=\"ql-align-right ql-direction-rtl\">تختار الصف الذي سيكون مرتبط به الفصل</li><li class=\"ql-align-right ql-direction-rtl\">ثم تكتب رقم القسم (الفصل)   ( ١ ) مثلاً </li><li class=\"ql-align-right ql-direction-rtl\">ثم تضغط على حفظ</li></ol><p class=\"ql-align-right ql-direction-rtl\">\n            </p><p class=\"ql-align-right ql-direction-rtl\"><em><img src=\"data:image/png;base64,\"></em>\n            </p><h2 class=\"ql-align-right ql-direction-rtl\">3. تخصيص المعلمين للفصول</h2><p class=\"ql-align-right ql-direction-rtl\">\n            </p><p class=\"ql-align-right ql-direction-rtl\">يمكنك الآن ربط كل معلم بالفصول التي يشرف عليها، مما يسهل عليه الوصول لبيانات طلابه فقط دون التداخل مع بقية المدرسة.</p><p class=\"ql-align-right ql-direction-rtl\">\n            </p><p class=\"ql-align-right ql-direction-rtl\"><em><img src=\"data:image/png;base64,\"></em>\n            </p><p class=\"ql-align-right ql-direction-rtl\">في الدرس القادم، سنتحدث عن <strong>إدارة المعلمين وتوزيع الصلاحيات</strong> لضمان سير العمل بسلاسة.</p><p class=\"ql-align-right ql-direction-rtl\">\n        </p>','تعلم كيفية تنظيم مدرستك تقنياً عبر إضافة المراحل الدراسية والفصول لضمان سهولة إدارة الطلاب والأنشطة.','http://localhost/pe1/uploads/media/media_1773005528_9cf895da6f.png','الدروس','published','2026-03-08 16:35:19',NULL,'2026-03-08 14:35:19','2026-03-09 07:18:30',1,NULL,0),(3,NULL,'الدرس الثالث: إدارة المعلمين ومنح الصلاحيات في منصة PE Smart School','teacher-management-permissions','\n            <p>النجاح في إدارة القسم الرياضي يعتمد على العمل الجماعي. في منصة <strong>PE Smart School</strong>، يمكنك إضافة زملائك من المعلمين ومنحهم الصلاحيات اللازمة للقيام بمهامهم بكفاءة.</p>\n            \n            <h2>1. إضافة معلم جديد</h2>\n            <p>لإضافة حساب لمعلم جديد، اتبع الخطوات التالية:</p>\n            <ul>\n                <li>توجه إلى قسم <strong>\"إدارة المستخدمين\"</strong>.</li>\n                <li>اضغط على زر \"إضافة مستخدم جديد\".</li>\n                <li>أدخل البيانات الأساسية (الاسم، اسم المستخدم، كلمة المرور).</li>\n                <li>تأكد من اختيار الرتبة <strong>\"معلم\" (Teacher)</strong>.</li>\n            </ul>\n            <p><em>[اقتراح صورة: نموذج إضافة معلم جديد مع اختيار الرتبة]</em></p>\n\n            <h2>2. توزيع الصلاحيات والمهام</h2>\n            <p>المنصة تميز بين نوعين من الحسابات:</p>\n            <ul>\n                <li><strong>المدير (Admin):</strong> يملك تحكماً كاملاً في إعدادات المدرسة، حذف البيانات، وإدارة الحسابات.</li>\n                <li><strong>المعلم (Teacher):</strong> تتركز صلاحياته في رصد الغياب، تسجيل القياسات، وإدارة التدريبات للفصول المسندة إليه.</li>\n            </ul>\n            <p><em>[اقتراح صورة: جدول مقارنة الصلاحيات أو واجهة تعديل مستخدم]</em></p>\n\n            <h2>3. ربط المعلم بالفصول</h2>\n            <p>بعد إضافة المعلم، من الضروري ربطه بالفصول التي يدرسها. هذا يضمن أن المعلم يرى فقط بيانات طلابه، مما يقلل من تشتت البيانات ويزيد من الأمان.</p>\n            <p><em>[اقتراح صورة: واجهة ربط المعلمين بالفصول]</em></p>\n\n            <h2>نصيحة تقنية</h2>\n            <p>ننصح بتغيير كلمات المرور بشكل دوري وتذكير المعلمين بعدم مشاركة حساباتهم لضمان خصوصية بيانات الطلاب الصحية والبدنية.</p>\n\n            <p>في الدرس القادم، سننتقل إلى الجانب العملي: <strong>رصد الحضور والغياب وإدارة الحصص اليومية</strong>.</p>\n        ','اكتشف كيفية إضافة فريق العمل الرياضي وتوزيع المهام والصلاحيات لضمان إدارة احترافية وآمنة لمدرستك.','https://images.unsplash.com/photo-1524178232363-1fb28f74b0cd?auto=format&fit=crop&q=80&w=1000','الدروس','published','2026-03-08 16:38:16',NULL,'2026-03-08 14:38:16','2026-03-09 07:18:47',1,NULL,0);
/*!40000 ALTER TABLE `blog_posts` ENABLE KEYS */;
