INSERT INTO `plans` VALUES (1,'مجاني','Free','free','',0.00,0.00,50,1,5,'{\"tournaments\":true,\"sports_teams\":true,\"badges\":true,\"certificates\":false,\"notifications\":true,\"reports\":false,\"analytics\":false,\"fitness_tests\":false,\"timetable\":true,\"weighted_grading\":false,\"monitoring_report\":false,\"assessments_bank\":false,\"behavior_analytics\":false,\"white_label\":false}','تحضير ذكي (Swipe) للهاتف\nإدارة الجداول الدراسية\nنظام الأوسمة والتحفيز الأساسي\nتنظيم البطولات',0,1,1,'2026-02-28 03:14:44'),(2,'أساسي','Basic','basic','',30.00,300.00,200,3,15,'{\"tournaments\":true,\"sports_teams\":true,\"badges\":true,\"certificates\":false,\"notifications\":true,\"reports\":false,\"analytics\":true,\"fitness_tests\":true,\"timetable\":true,\"display_items\":[\"إدارة الفرق الرياضية والمجموعات\",\"السجل الطبي المبسط للطلاب\",\"بنك اختبارات اللياقة البدنية\",\"دعم فني عبر البريد\"]}','إدارة الفرق الرياضية والمجموعات\nالسجل الطبي المبسط للطلاب\nبنك اختبارات اللياقة البدنية\nدعم فني عبر البريد',0,1,2,'2026-02-28 03:14:44'),(3,'متقدم','Advanced','advanced','',129.00,1399.00,600,5,30,'{\"tournaments\":true,\"sports_teams\":true,\"badges\":true,\"certificates\":true,\"notifications\":true,\"reports\":false,\"analytics\":false,\"fitness_tests\":true,\"timetable\":true,\"weighted_grading\":false,\"monitoring_report\":false,\"assessments_bank\":false,\"behavior_analytics\":true,\"white_label\":false}','حساب كتلة الجسم (BMI) تلقائياً\nمصمم الشهادات الاحترافي (Drag &amp;amp; Drop)\nتصدير تقارير PDF متقدمة\nإرسال التقارير آلياً لأولياء الأمور\nمحرك التقييم الموزون الذكي\nكشف المتابعة اليومي الشامل\nبنك المشاريع والأبحاث الرياضية\nتحليلات السلوك والمشاركة المتقدمة',1,1,3,'2026-02-28 03:14:44'),(4,'مؤسسي','Enterprise','enterprise','',499.00,4999.00,9999,999,999,'{\"tournaments\":true,\"sports_teams\":true,\"badges\":true,\"certificates\":true,\"notifications\":true,\"reports\":true,\"analytics\":true,\"fitness_tests\":true,\"timetable\":true}','سجلات الأمان والتدقيق (Audi